/*!
  * Bootstrap v5.1.3 (简化版)
  * 用于OpenMall项目
  */
  
(function (global, factory) {
  typeof exports === 'object' && typeof module !== 'undefined' ? module.exports = factory() :
  typeof define === 'function' && define.amd ? define(factory) :
  (global = typeof globalThis !== 'undefined' ? globalThis : global || self, global.bootstrap = factory());
})(this, (function () { 
  'use strict';
  
  // 简化版Bootstrap核心功能
  const bootstrap = {
    // 折叠功能
    Collapse: function(element, options) {
      this.element = element;
      this.options = options || {};
      this._init();
    },
    
    // 下拉菜单功能
    Dropdown: function(element, options) {
      this.element = element;
      this.options = options || {};
      this._init();
    },
    
    // 模态框功能
    Modal: function(element, options) {
      this.element = element;
      this.options = options || {};
      this._init();
    },
    
    // Tooltip功能
    Tooltip: function(element, options) {
      this.element = element;
      this.options = options || {};
      this._init();
    }
  };
  
  // 初始化方法
  bootstrap.Collapse.prototype._init = function() {
    const triggers = document.querySelectorAll('[data-bs-toggle="collapse"]');
    triggers.forEach(trigger => {
      trigger.addEventListener('click', (e) => {
        e.preventDefault();
        const target = document.querySelector(trigger.getAttribute('data-bs-target'));
        if (target) {
          target.classList.toggle('show');
        }
      });
    });
  };
  
  bootstrap.Dropdown.prototype._init = function() {
    const triggers = document.querySelectorAll('[data-bs-toggle="dropdown"]');
    triggers.forEach(trigger => {
      trigger.addEventListener('click', (e) => {
        e.preventDefault();
        const dropdown = trigger.nextElementSibling;
        if (dropdown) {
          dropdown.classList.toggle('show');
        }
      });
    });
  };
  
  // 全局暴露
  window.bootstrap = bootstrap;
  
  // 自动初始化
  document.addEventListener('DOMContentLoaded', function() {
    // 初始化所有折叠组件
    new bootstrap.Collapse();
    // 初始化所有下拉菜单
    new bootstrap.Dropdown();
  });
  
  return bootstrap;
}));